async function detectHandsOnImage(
  img: HTMLImageElement
): Promise<LmPt[][] | null> {
  const HW = window.Hands as unknown as HandsCtor | undefined;
  if (!HW) {
    await loadScript(CDN_HANDS_URL);
  }

  const HF = window.Hands as unknown as HandsCtor | undefined;
  if (!HF) {
    throw new Error("MediaPipe Hands failed to initialize");
  }

  const hands = new HF({ locateFile: (f) => CDN_BASE + f });
  hands.setOptions({
    maxNumHands: 1,
    modelComplexity: 1,
    minDetectionConfidence: 0.3,
    minTrackingConfidence: 0.3,
  });

  const maxDim = 640;
  const scale = Math.min(1, maxDim / Math.max(img.naturalWidth, img.naturalHeight));
  const canvasW = Math.round(img.naturalWidth * scale);
  const canvasH = Math.round(img.naturalHeight * scale);

  const canvas = document.createElement("canvas");
  canvas.width = canvasW;
  canvas.height = canvasH;
  const ctx = canvas.getContext("2d");
  if (!ctx) {
    hands.close();
    throw new Error("Canvas 2D context is unavailable");
  }
  ctx.fillStyle = "#fff";
  ctx.fillRect(0, 0, canvasW, canvasH);
  ctx.drawImage(img, 0, 0, canvasW, canvasH);

  let stream: MediaStream | null = null;
  try {
    stream = canvas.captureStream(10);
  } catch {
    stream = null;
  }

  async function detectOnce(src: HTMLCanvasElement): Promise<HandsResults> {
    return new Promise((resolve, reject) => {
      const timer = setTimeout(() => reject(new Error("Hand detection timed out")), DETECT_TIMEOUT);
      hands.onResults((result) => {
        clearTimeout(timer);
        resolve(result);
      });
      hands.send({ image: src }).catch((error) => {
        clearTimeout(timer);
        reject(error);
      });
    });
  }

  let lastError: string | null = null;

  for (let attempt = 0; attempt < 3; attempt += 1) {
    try {
      if (stream) {
        const video = document.createElement("video");
        video.srcObject = stream;
        video.width = canvasW;
        video.height = canvasH;

        await new Promise<void>((resolve) => {
          video.onloadedmetadata = () => {
            video.play().then(() => resolve()).catch(() => resolve());
          };
          setTimeout(resolve, 2000);
        });

        try {
          await detectOnce(canvas);
        } catch {
        }

        const results = await detectOnce(canvas);
        if (results.multiHandLandmarks?.length) {
          stream.getTracks().forEach((track) => track.stop());
          hands.close();
          return results.multiHandLandmarks;
        }
      } else {
        if (attempt === 0) {
          try {
            await detectOnce(canvas);
          } catch {
          }
        }

        const results = await detectOnce(canvas);
        if (results.multiHandLandmarks?.length) {
          hands.close();
          return results.multiHandLandmarks;
        }
      }
    } catch (error) {
      lastError = error instanceof Error ? error.message : String(error);
      console.warn(`[NailArtPicker] Attempt ${attempt + 1} failed:`, lastError);
      if (attempt < 2) {
        await new Promise((resolve) => setTimeout(resolve, 1000));
      }
    }
  }

  if (stream) {
    stream.getTracks().forEach((track) => track.stop());
  }
  hands.close();
  console.warn("[NailArtPicker] All attempts failed, last error:", lastError);
  return null;
}

async function extractNailFromRegion(
  img: HTMLImageElement,
  region: NailRegion,
  displayScale: number
): Promise<ImageBitmap> {
  if (displayScale <= 0) throw new Error("Invalid display scale for texture extraction");
  const original = mapGeometryScale(
    {
      cx: region.cx,
      cy: region.cy,
      length: region.nl,
      width: region.nw,
      angle: region.angle,
    },
    1 / displayScale
  );
  const outputWidth = Math.max(4, Math.ceil(original.width));
  const outputHeight = Math.max(4, Math.ceil(original.length));
  const canvas = new OffscreenCanvas(outputWidth, outputHeight);
  const ctx = canvas.getContext("2d")!;
  ctx.translate(outputWidth / 2, outputHeight / 2);
  drawNailPath(ctx, original.length, original.width);
  ctx.clip();
  ctx.rotate(-original.angle);
  ctx.drawImage(img, -original.cx, -original.cy);
  return createImageBitmap(canvas);
}

