function clientToCanvas(cx: number, cy: number, cvs: HTMLCanvasElement) {
  const r = cvs.getBoundingClientRect();
  return { x: (cx - r.left) * (cvs.width / r.width), y: (cy - r.top) * (cvs.height / r.height) };
}

